/**
 * Agent Chat API
 *
 * API functions for agent chat operations.
 * Uses the client passed in from the provider.
 */
import { isAdHocConfig, extractToolSchemas } from './types';
/**
 * Check if input is an already-uploaded file
 */
function isFileRef(input) {
    return 'uri' in input && typeof input.uri === 'string';
}
/**
 * Send a message using ad-hoc agent config
 */
export async function sendAdHocMessage(client, config, chatId, text, attachments) {
    // Extract just the schemas from tools (handlers are stripped out)
    const toolSchemas = config.tools ? extractToolSchemas(config.tools) : undefined;
    const request = {
        chat_id: chatId ?? undefined,
        agent_config: {
            ...config,
            system_prompt: config.system_prompt ?? '',
            tools: toolSchemas
        },
        agent_name: config.name,
        input: {
            text,
            attachments,
            context_size: 0,
            system_prompt: '',
            context: [],
            role: 'user',
        },
    };
    const response = await client.http.request('post', '/agents/run', { data: request });
    if (response) {
        const { user_message, assistant_message } = response;
        if (user_message && assistant_message) {
            return {
                chatId: assistant_message.chat_id,
                userMessage: user_message,
                assistantMessage: assistant_message,
            };
        }
    }
    return null;
}
/**
 * Send a message using template agent config
 */
export async function sendTemplateMessage(client, config, chatId, text, attachments) {
    const request = {
        chat_id: chatId ?? undefined,
        // Only include agent if it's not empty (for existing chats, backend uses chat's agent)
        agent: config.agent || undefined,
        input: {
            text,
            attachments,
            context_size: 0,
            system_prompt: '',
            context: [],
            role: 'user',
        },
    };
    const response = await client.http.request('post', '/agents/run', { data: request });
    if (response) {
        const { user_message, assistant_message } = response;
        if (user_message && assistant_message) {
            return {
                chatId: assistant_message.chat_id,
                userMessage: user_message,
                assistantMessage: assistant_message,
            };
        }
    }
    return null;
}
/**
 * Send a message (unified interface)
 */
export async function sendMessage(client, config, chatId, text, files) {
    // Process files - upload if needed, collect as FileRef attachments
    let attachments;
    if (files && files.length > 0) {
        attachments = [];
        for (const file of files) {
            // Check if already uploaded (FileRef)
            if (isFileRef(file)) {
                attachments.push(file);
                continue;
            }
            // Upload the file
            try {
                const result = await client.files.upload(file);
                if (result) {
                    attachments.push(result);
                }
            }
            catch (error) {
                console.error('[AgentSDK] Failed to upload file:', error);
            }
        }
        if (attachments.length === 0) {
            attachments = undefined;
        }
    }
    if (isAdHocConfig(config)) {
        return sendAdHocMessage(client, config, chatId, text, attachments);
    }
    else {
        return sendTemplateMessage(client, config, chatId, text, attachments);
    }
}
/**
 * Fetch a chat by ID
 */
export async function fetchChat(client, chatId) {
    try {
        return await client.http.request('get', `/chats/${chatId}`);
    }
    catch (error) {
        console.error('[AgentSDK] Failed to fetch chat:', error);
    }
    return null;
}
/**
 * Stop a chat
 */
export async function stopChat(client, chatId) {
    try {
        await client.http.request('post', `/chats/${chatId}/stop`);
    }
    catch (error) {
        console.error('[AgentSDK] Failed to stop chat:', error);
    }
}
/**
 * Submit a tool result (for client tools/widgets/awaiting input)
 */
export async function submitToolResult(client, toolInvocationId, resultOrAction) {
    try {
        const data = typeof resultOrAction === 'string' ? { result: resultOrAction } : resultOrAction;
        await client.http.request('post', `/tools/${toolInvocationId}`, { data });
    }
    catch (error) {
        console.error('[AgentSDK] Failed to submit tool result:', error);
        throw error;
    }
}
/**
 * Approve a tool (for HIL approval)
 */
export async function approveTool(client, toolInvocationId) {
    try {
        await client.http.request('post', `/tools/${toolInvocationId}/invoke`);
    }
    catch (error) {
        console.error('[AgentSDK] Failed to approve tool:', error);
        throw error;
    }
}
/**
 * Reject a tool (for HIL approval)
 */
export async function rejectTool(client, toolInvocationId, reason) {
    try {
        await client.http.request('post', `/tools/${toolInvocationId}/reject`, { data: { reason } });
    }
    catch (error) {
        console.error('[AgentSDK] Failed to reject tool:', error);
        throw error;
    }
}
/**
 * Always allow a tool for this chat
 */
export async function alwaysAllowTool(client, chatId, toolInvocationId, toolName) {
    try {
        await client.http.request('post', `/chats/${chatId}/tools/${toolInvocationId}/always-allow`, {
            data: { tool_name: toolName }
        });
    }
    catch (error) {
        console.error('[AgentSDK] Failed to always-allow tool:', error);
        throw error;
    }
}
/**
 * Upload a file and return the uploaded file reference
 */
export async function uploadFile(client, file) {
    const result = await client.files.upload(file);
    return result;
}
/**
 * Get streamable config for chat streaming (NDJSON)
 */
export function getChatStreamConfig(client, chatId) {
    return client.http.getStreamableConfig(`/chats/${chatId}/stream`);
}
